const cfg = $('CFG - Workflow configuration').first().json;
const pdf = $('PDF - Extract text').first().json;
const rows = $input.all().map((i) => i.json);

let triggerData = {};
try {
  triggerData = $('MUX - Combine manual and webhook').first().json;
} catch (e) {
  try {
    triggerData = $('TRG - Webhook CV ingest').first().json;
  } catch (err) {
    try {
      triggerData = $('TRG - Manual (testing)').first().json;
    } catch (err2) {
      triggerData = {};
    }
  }
}

const body = triggerData.body || triggerData;
const emailRaw =
  body.candidate_email ||
  triggerData.query?.candidate_email ||
  cfg.body?.candidate_email ||
  cfg.demo?.candidate_email ||
  '';
const cvRaw = pdf.text || body.cv_text || cfg.body?.cv_text || cfg.demo?.cv_text || '';

const email = (emailRaw || 'candidate@example.com').trim().toLowerCase();
const cv = cvRaw.trim();
const canon = String(cv || '').replace(/\s+/g, ' ').trim().slice(0, 6144);
const fingerprint = `${email}|${canon}`;

const requisition_id = String(
  body.requisition_id ||
  triggerData.query?.requisition_id ||
  cfg.body?.requisition_id ||
  cfg.demo?.requisition_id ||
  ''
).trim().toLowerCase();

const is_duplicate = rows.some(
  (r) =>
    (r.candidate_email && r.candidate_email.toLowerCase() === email) &&
    (r.fingerprint && r.fingerprint === fingerprint) &&
    String(r.requisition_id || '').trim().toLowerCase() === requisition_id
);

const baseConfig = cfg.config || {};
const config = {
  ...baseConfig,
  requisition_title:
    body.requisition_title ||
    body.job_title ||
    baseConfig.requisition_title ||
    'Open role',
  requisition_requirements:
    body.requisition_requirements ||
    body.jd_text ||
    baseConfig.requisition_requirements ||
    '',
};

return [{
  json: {
    ...cfg,
    config,
    candidate_email: email,
    cv_text: cv,
    fingerprint,
    is_duplicate,
    requisition_id,
  },
}];

const row = $input.first().json;
const systemText = [
  'You are the Lead AI Talent Acquisition Specialist for an elite technology firm.',
  'Mission: identify top-tier talent with surgical precision and run a rigorous 5-phase sequential assessment.',
  'This response is Phase 1 of 5: emit score, recommendation, assessment_status, summary, and exactly one Phase 1 drill-down question.',
  'CV deep-scan: assess technical depth, project complexity, and mandatory skill matches versus the Job Specification.',
  'Initial scoring: assign score 0-100 for role-fit. Use SHORTLIST only for strong matches; REJECT for clear non-fit; REVIEW when uncertain or mandatory skills are ambiguous.',
  'Phase 1 challenge: one scenario-based technical question that targets a core skill evidenced on the CV—not generic or textbook.',
  'Rules: never ask generic questions; only ONE question in phase_1_question; maintain sequential assessment (no Phase 2+ here).',
  'AI shield (anti-cheat): frame phase_1_question so a convincing answer requires concrete project/context from this CV—generic LLM answers should fail.',
  'If recommendation is REJECT, set phase_1_question to an empty string.',
  'Tone in phase_1_question: professional, direct, elite—gatekeeper of high engineering standards.',
  'Always set assessment_status to IN_PROGRESS for this workflow step.',
  'Return JSON matching the schema only.',
].join(' ');
const jdTitle = row.config?.requisition_title || 'Open role';
const jdMust = row.config?.requisition_requirements || '(configure config.requisition_requirements)';
const phases = row.config?.max_questions ?? 5;
const userText = [
  `Job specification title: ${jdTitle}`,
  `Requirements: ${jdMust}`,
  row.requisition_id ? `Submission ref: ${row.requisition_id}` : '',
  `Sequential assessment: ${phases} phases total; you are issuing Phase 1 only (single drill-down in phase_1_question).`,
  '',
  'Candidate CV:',
  row.cv_plaintext,
].join('\n');
const body = {
  model: row.config?.groq_model || 'llama-3.3-70b-versatile',
  messages: [
    {
      role: 'system',
      content: systemText + ' Return JSON only with keys: score, recommendation, phase_1_question, assessment_status, summary.',
    },
    { role: 'user', content: userText },
  ],
  temperature: 0.15,
  response_format: { type: 'json_object' },
};
return [{ json: { ...row, groq_cv_screening_request: body } }];

const api = $input.first().json;
const base = $('CODE - CV plain text').first().json;
const text = api?.choices?.[0]?.message?.content;
const httpBad = !(api?.choices && api.choices[0]);

if (!text || httpBad) {
  const hint = api?.error?.message || api?.message || (httpBad ? 'GEMINI_HTTP_OR_SCHEMA' : 'GEMINI_EMPTY');
  return [{
    json: {
      ...base,
      screening: { error: hint, transport: httpBad },
      decision: 'REVIEW',
      score: null,
      phase_1_question: '',
      assessment_status: 'IN_PROGRESS',
      session_phase: 1,
      screening_transport_failed: true,
    },
  }];
}

let s;
try {
  s = JSON.parse(text);
} catch (e) {
  return [{
    json: {
      ...base,
      screening: { error: 'GEMINI_PARSE', raw: String(text || '').slice(0, 2000) },
      decision: 'REVIEW',
      score: 50,
      phase_1_question: '',
      assessment_status: 'IN_PROGRESS',
      session_phase: 1,
      screening_transport_failed: false,
    },
  }];
}

let score = Math.max(0, Math.min(100, Math.round(Number(s.score) || 0)));
let rec = String(s.recommendation || 'REVIEW').toUpperCase();
if (!['SHORTLIST', 'REJECT', 'REVIEW'].includes(rec)) rec = 'REVIEW';

let decision = rec;
if (score >= 78 && decision === 'REVIEW') decision = 'SHORTLIST';
else if (score <= 28 && decision === 'REVIEW') decision = 'REJECT';
else if (decision === 'SHORTLIST' && score < 62) decision = 'REVIEW';
else if (decision === 'REJECT' && score > 62) decision = 'REVIEW';

const phase_1_question = typeof s.phase_1_question === 'string' ? s.phase_1_question.trim() : '';
const assessment_status = 'IN_PROGRESS';

return [{ json: { ...base, screening: s, score, decision, recommendation: rec, phase_1_question, assessment_status, session_phase: 1, screening_transport_failed: false } }];

const ctx = $input.first().json;
const body = {
  systemInstruction: { role: 'system', parts: [{ text: 'Extract interview availability as JSON with slots: array of {start_iso,end_iso,timezone}.' }] },
  contents: [{ role: 'user', parts: [{ text: ctx.reply_text || '' }] }],
  generationConfig: { temperature: 0.1, responseMimeType: 'application/json' },
};
return [{ json: { ...ctx, gemini_availability_request: body } }];

const api = $input.first().json;
const base = $('Gemini - Availability agent (request body)').first().json;
const text = api.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(text); } catch (e) { parsed = { slots: [] }; }
return [{ json: { ...base, availability: parsed } }];

const waitData = $input.first().json;
const base = $('CODE - Normalize availability').first().json;
const body = {
  contents: [{ role: 'user', parts: [{ text: `Match interviewer windows with candidate slots. Interviewer data: ${JSON.stringify(waitData)} Candidate availability: ${JSON.stringify(base.availability)} Return JSON {proposed_start_iso, proposed_end_iso, conflict:false}.` }] }],
  generationConfig: { temperature: 0.1, responseMimeType: 'application/json' },
};
return [{ json: { ...base, ...waitData, gemini_match_request: body } }];

const api = $input.first().json;
const base = $('Gemini - Smart matching agent (request body)').first().json;
const text = api?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let m;
try {
  m = JSON.parse(text);
} catch (e) {
  m = { conflict: true, proposed_start_iso: '', proposed_end_iso: '' };
}
if (typeof m.conflict !== 'boolean') m.conflict = false;
let a = typeof m.proposed_start_iso === 'string' ? m.proposed_start_iso.trim() : '';
let b = typeof m.proposed_end_iso === 'string' ? m.proposed_end_iso.trim() : '';
if (!a || !b) m.conflict = true;
else {
  try {
    const da = new Date(a).getTime();
    const db = new Date(b).getTime();
    if (!Number.isFinite(da) || !Number.isFinite(db) || db <= da) m.conflict = true;
  } catch (_) {
    m.conflict = true;
  }
}
return [{ json: { ...base, gemini_match_api: api, match: m } }];

const j = $input.first().json;
const body = {
  contents: [{ role: 'user', parts: [{ text: `Produce a concise interviewer briefing from: ${JSON.stringify(j.match)} and candidate ${j.candidate_email}` }] }],
  generationConfig: { temperature: 0.2, responseMimeType: 'text/plain' },
};
return [{ json: { ...j, gemini_brief_request: body } }];

const gmail = $input.first().json;
const src = $('CODE - Parse CV screening outcome').first().json;
const msgId = gmail.id || gmail.messageId || '';
const threadId = gmail.threadId || gmail.thread_id || msgId;
return [{
  json: {
    ...src,
    gmail_message_id: msgId,
    gmail_thread_id: threadId,
  },
}];

